<template>
    <div class="demo-content">
        <h1>mapbox添加3D模型</h1>
        <h4>Tip:以下地图坐标从高德地图拾取,需要进行坐标转换</h4>
        <h2>添加3D模型</h2>
        <div class="field">
            <div class="field-left">
                <pre>
                    <code-copy :code="threeCode" :btnClssName="'copy-btn'"></code-copy>
                    <code>{{threeCode}}</code>
                </pre>
            </div>
            <div class="field-right">
                <base-map :mapOptions="mapOptions" :hasThreeModel="true" @getMap="getMap($event)" @getTb="getTb($event)"></base-map>
            </div>
        </div>
    </div>
</template>

<script>
import BaseMap from "../../components/BaseMap.vue";
import CodeCopy from "../../components/CodeCopy.vue";
import { reactive, ref, onMounted, onUpdated, onBeforeUnmount } from "vue";
import { Utils } from "../../utils/utils";
import coordtransform from "coordtransform";

export default {
    components: {
        BaseMap,
        CodeCopy
    },
    setup() {
        const mapOptions = reactive({
            center: {
                lon: 118.784135,
                lat: 32.041808
            },
            zoom: 17,
            pitch: 60
        });
        let map = reactive(null);
        let tb = reactive(null);
        let busModels = reactive([]);
        let modelsMap = reactive({});
        const gpsData = reactive([{ lon: 118.784135, lat: 32.041808, type: "srt" }]);

        const getMap = data => {
            map = data;
        };

        const getTb = data => {
            tb = data;
            addThreeLayer();
        };

        const threeCode = ref(`// 添加3D模型图层
const addThreeLayer = () => {
    map.addLayer({
        id: "custom_layer",
        type: "custom",
        renderingMode: "3d",
        onAdd: () => {
            loadModels().then((models) => {
                modelsMap = {};
                models.forEach((item) => {
                    modelsMap[item.name] = item.model;
                });
                addModelsToMap();
            });
        },
        render: () => {
            tb.update();
        }
    });
};

// 加载模型
const loadModels = () => {
    const modelUrls = [
        { url: "../../assets/models/srt.gltf", name: "srt" },
        { url: "../../assets/models/brt.gltf", name: "brt" }
    ];
    const promiseArray = [];
    modelUrls.forEach((item) => {
        const option = {
            obj: item.url,
            type: "gltf",
            scale: { x: 3, y: 3, z: 3 },
            units: "meters",
            adjustment: { x: 0.5, y: 0.5, z: 0 }, //三维模型通常不在其轴的中心，因此对象的位置和旋转错误。调整参数必须以每个轴的单位提供（即调整：{x:0.5，y:0.5，z:0}），因此模型将校正对象的中心位置
            rotation: { x: 90, y: 0, z: 0 } // default rotation
        };
        promiseArray.push(
            new Promise((resolve) => {
                tb.loadObj(option, (model) => {
                    resolve({
                        model,
                        name: item.name
                    });
                });
            })
        );
    });
    return Promise.all(promiseArray);
};

// 添加模型到地图上
const addModelsToMap = () => {
    gpsData.forEach((item) => {
        const model = modelsMap[item.type]
            .duplicate()
            .setCoords(coordtransform.gcj02towgs84(item.lon, item.lat));
        // 默认为逆时针旋转
        model.setRotation({
            x: 0,
            y: 0,
            z: -Math.floor(Math.random() * 360)
        });
        let labelDiv = "<h1 style='color:blue'>这是标签</h1>";
        model.addLabel(labelDiv, true, model.anchor, 1);
        tb.add(model);
        busModels.push(model);
    });
    map.triggerRepaint();
};

// 清除模型
const clearBusModels = () => {
    busModels.forEach((item) => {
        tb.remove(item);
    });
    busModels = [];
    if (tb) {
        tb.update();
    }
    map.triggerRepaint();
};
        `);

        // 添加3D模型图层
        const addThreeLayer = () => {
            map.addLayer({
                id: "custom_layer",
                type: "custom",
                renderingMode: "3d",
                onAdd: () => {
                    loadModels().then(models => {
                        modelsMap = {};
                        models.forEach(item => {
                            modelsMap[item.name] = item.model;
                        });
                        addModelsToMap();
                    });
                },
                render: () => {
                    if (map) {
                        tb.update();
                    }
                }
            });
        };

        // 添加模型到地图上
        const addModelsToMap = () => {
            gpsData.forEach(item => {
                const model = modelsMap[item.type].duplicate().setCoords(coordtransform.gcj02towgs84(item.lon, item.lat));
                // 默认为逆时针旋转
                model.setRotation({
                    x: 0,
                    y: 0,
                    z: -Math.floor(Math.random() * 360)
                });
                let labelDiv = `<h1 style="color:blue">这是标签</h1>`;
                model.addLabel(labelDiv, true, model.anchor, 1);
                tb.add(model);
                busModels.push(model);
            });
            map.triggerRepaint();
        };

        // 加载模型
        const loadModels = () => {
            const modelUrls = [
                { url: location.origin + "/assets/models/srt.gltf", name: "srt" },
                { url: location.origin + "/assets/models/brt.gltf", name: "brt" }
            ];
            const promiseArray = [];
            modelUrls.forEach(item => {
                const option = {
                    obj: item.url,
                    type: "gltf",
                    scale: { x: 3, y: 3, z: 3 },
                    units: "meters",
                    anchor: "center",
                    tooltip: false,
                    // adjustment: { x: 0.5, y: 0.5, z: 0 }, //三维模型通常不在其轴的中心，因此对象的位置和旋转错误。调整参数必须以每个轴的单位提供（即调整：{x:0.5，y:0.5，z:0}），因此模型将校正对象的中心位置
                    rotation: { x: 90, y: 0, z: 0 } // default rotation
                };
                promiseArray.push(
                    new Promise(resolve => {
                        tb.loadObj(option, model => {
                            resolve({
                                model,
                                name: item.name
                            });
                        });
                    })
                );
            });
            return Promise.all(promiseArray);
        };

        // 清除模型
        const clearBusModels = () => {
            busModels.forEach(item => {
                tb.remove(item);
            });
            busModels = [];
            if (tb) {
                tb.update();
            }
            if (map) {
                map.triggerRepaint();
            }
        };
        onMounted(() => {
            Utils.highlightCode();
        });

        onUpdated(() => {
            Utils.highlightCode();
        });

        onBeforeUnmount(() => {
            clearBusModels();
        });

        return {
            mapOptions,
            getMap,
            threeCode,
            gpsData,
            Utils,
            getTb
        };
    }
};
</script>

<style lang="scss" scoped>
.demo-content {
    width: 100%;
    height: 100%;
    padding: 16px;
    overflow: auto;
    display: flex;
    flex-direction: column;

    .field {
        display: flex;
        width: 100%;
        height: 700px;
        margin: 16px 0;
        flex: 1;
        height: 0;

        .field-left {
            flex: 1;
            height: 100%;
            width: 0;

            pre {
                margin: 0;
                padding: 0;
                height: 100%;
                display: flex;
                width: 100%;
                position: relative;

                code {
                    width: 100%;
                }
            }
        }

        .field-right {
            margin-left: 16px;
            width: 50%;
            height: 100%;
        }
    }
}
</style>
